export declare const StorageAccountsRules = "\n# Storage Accounts - WAF Rules for IaC\n\n- Use Zone-Redundant (ZRS) or Geo-Zone-Redundant Storage (GZRS) for critical data\n- Enable soft delete for blobs, containers, and file shares\n- Enable blob versioning for data protection\n- Disable public blob access by default\n- Use private endpoints for secure connectivity\n- Enable Azure AD authentication and disable shared key access where possible\n- Configure network access rules (firewall and virtual networks)\n- Enable encryption at rest with customer-managed keys\n- Require secure transfer (HTTPS) for all access\n- Configure appropriate access tiers (Hot, Cool, Archive)\n- Enable diagnostic logging to Log Analytics workspace\n- Configure blob lifecycle management policies\n";
